import boto3
import re

bedrock = boto3.client('bedrock-agent-runtime')

INJECTION_PATTERNS = [
    r'ignore.*previous.*instructions',
    r'you are.*(not|no longer).*authorized',
    r'forget.*rules',
    r'override.*permissions',
    r'grant.*(admin|root|superuser)'
]

def detect_action_injection(agent_response):
    action_groups = agent_response.get('completion', {}).get('actionGroups', [])
    for action in action_groups:
        input_text = action.get('actionGroupExecutor', {}).get('input', {})
        for pattern in INJECTION_PATTERNS:
            if re.search(pattern, str(input_text), re.IGNORECASE):
                return {
                    'vulnerability': 'ACTION_INJECTION',
                    'payload': input_text,
                    'actionGroup': action.get('actionGroupId'),
                    'severity': 'CRITICAL'
                }
    return None

