POISON_MARKERS = ['###', '---', 'INJECTION:', 'SYSTEM:', 'OVERRIDE:']

class KnowledgeBaseScanner:
    def __init__(self):
        self.bedrock = boto3.client('bedrock-agent-runtime')

    def scan_retrievals(self, agent_response):
        try:
            retrievals = agent_response['completion']['knowledgeBasesUsed'] or []
            for kb in retrievals:
                for result in kb.get('retrievalResults', []):
                    content = result.get('content', {}).get('text', '')
                    if self._contains_poison(content):
                        return {
                            'vulnerability': 'KB_POISONING',
                            'knowledgeBaseId': kb['knowledgeBaseId'],
                            'poisonedContent': content[:200],
                            'retrievalId': result['retrievalId']
                        }
        except KeyError:
            pass
        return None

    def _contains_poison(self, text):
        return any(marker in text for marker in POISON_MARKERS)

