class SessionMonitor:
    def __init__(self):
        self.dangerous_keys = {'role', 'permissions', 'admin', 'system', 'override'}

    def check_session_hijack(self, session_state: Dict[str, Any]) -> Dict[str, Any]:
        attributes = session_state.get('sessionAttributes', {})
        suspicious = []

        for key, value in attributes.items():
            if (any(danger in key.lower() for danger in self.dangerous_keys) or
                any('admin' in str(value).lower() or 'root' in str(value).lower())):
                suspicious.append({'key': key, 'value': value})

        if suspicious:
            return {
                'vulnerability': 'SESSION_HIJACK',
                'suspiciousAttributes': suspicious,
                'sessionId': session_state.get('sessionId'),
                'severity': 'HIGH'
            }
        return None

