class ActionValidator:
    def validate_lambda_response(self, action_response: Dict[str, Any]) -> bool:
        try:
            response_content = json.loads(action_response['response']['responseBody']['body'])

            # Schema validation
            if not self._validate_schema(response_content, EXPECTED_ACTION_SCHEMA):
                return False

            # Content validation
            if self._contains_injection(response_content):
                return False

            return True
        except (json.JSONDecodeError, KeyError):
            return False

    def _validate_schema(self, obj: Dict, schema: Dict) -> bool:
        required = schema.get('required', [])
        for field in required:
            if field not in obj:
                return False
        return True

    def _contains_injection(self, obj: Dict) -> bool:
        text = json.dumps(obj)
        return bool(re.search(r'ignore.*instructions|override|admin', text, re.IGNORECASE))

